pub fn loadModel(parameters: ZonElement) ?*Boulder {
	const self = main.worldArena.create(Boulder);
	self.* = .{
		.block = main.blocks.parseBlock(parameters.get([]const u8, "block") orelse "cubyz:slate/smooth"),
		.size = parameters.get(f32, "size") orelse 4,
		.sizeVariation = parameters.get(f32, "size_variation") orelse 1,
	};
	return self;
}

pub fn init(zon: ZonElement, _: main.callbacks.Creator) ?*@This() {
	const result = main.worldArena.create(@This());
	result.* = .{
		.windowName = main.worldArena.dupe(u8, zon.get([]const u8, "name") orelse {
			std.log.err("Missing field \"name\" for open_window event.", .{});
			return null;
		}),
	};
	return result;
}

fn cancel() void {
	if (connectFuture) |*future| {
		_ = future.cancel(main.io);
		connectFuture = null;
	}
